function statsOf(data) {
  const sum = (arr, key = 'amount') => arr.reduce((s, x) => s + num(x[key]), 0);
  const saving = sum(data.savings) + num(data.motorcycle?.saved);
  const itemsTotal = data.items.reduce((s, x) => s + itemPrice(x), 0);
  const target = itemsTotal || num(data.settings.targetBudget);
  const bought = data.items.filter((x) => ['Satın Alındı', 'Kuruldu'].includes(x.status));
  const favoriteItems = data.items.filter((x) => x.favorite && itemPrice(x) > 0);
  const days = daysLeft(data.settings.targetDate);
  const left = Math.max(0, target - saving);
  const gtaItemsTotal = data.items.filter(isGtaSetItem).reduce((s, x) => s + itemPrice(x), 0);
  const gtaGoalTotal = (data.gtaGoal.items || []).reduce((s, x) => s + num(x.cost), 0);
  return {
    income: sum(data.incomes), expense: sum(data.expenses), saving, target, left, days,
    progress: pct(saving, target), daily: days ? Math.ceil(left / days) : left, weekly: days ? Math.ceil(left / days) * 7 : left, monthly: days ? Math.ceil(left / days) * 30 : left,
    todayIncome: data.incomes.filter((x) => isToday(x.date)).reduce((s, x) => s + num(x.amount), 0), todayExpense: data.expenses.filter((x) => isToday(x.date)).reduce((s, x) => s + num(x.amount), 0),
    monthIncome: data.incomes.filter((x) => isMonth(x.date)).reduce((s, x) => s + num(x.amount), 0), monthExpense: data.expenses.filter((x) => isMonth(x.date)).reduce((s, x) => s + num(x.amount), 0),
    weekIncome: data.incomes.filter((x) => isWeek(x.date)).reduce((s, x) => s + num(x.amount), 0), weekExpense: data.expenses.filter((x) => isWeek(x.date)).reduce((s, x) => s + num(x.amount), 0), monthSavings: data.savings.filter((x) => isMonth(x.date)).reduce((s, x) => s + num(x.amount), 0),
    debtLeft: Math.max(0, sum(data.debts) - sum(data.debts, 'paid')),
    itemsTotal, boughtTotal: bought.reduce((s, x) => s + itemPrice(x), 0), boughtCount: bought.length, itemsLeft: Math.max(0, itemsTotal - bought.reduce((s, x) => s + itemPrice(x), 0)), favoriteItems, favoriteTotal: favoriteItems.reduce((s, x) => s + itemPrice(x), 0),
    gtaDays: gtaCountdown().days, gtaTotal: gtaItemsTotal || gtaGoalTotal, taskPct: pct(data.checklist.filter((x) => x.done).length, data.checklist.length),
  };
}
function groupItems(items) { const extra = [...new Set(items.map((x) => normalizeCategory(x.category)).filter((x) => !itemCategories.includes(x)))]; return [...itemCategories, ...extra].map((cat) => [cat, items.filter((x) => normalizeCategory(x.category) === cat)]).filter(([, arr]) => arr.length); }
function groupSum(list) { const out = {}; list.forEach((x) => { const k = normalizeCategory(x.category || 'Manuel'); out[k] = (out[k] || 0) + num(x.amount); }); return Object.entries(out).sort((a, b) => b[1] - a[1]); }

