  async function requestDownloadFolder() { const access = FileSystem.StorageAccessFramework; if (!access?.requestDirectoryPermissionsAsync || !access?.createFileAsync) throw new Error('Download klasörü seçimi desteklenmiyor'); const perm = await access.requestDirectoryPermissionsAsync(); if (!perm.granted) throw new Error('Download klasörü izni verilmedi'); return perm.directoryUri; }
